#include <check.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

/*
 * Security invariant: Buffer reads/copies never exceed the declared destination
 * buffer length. When copying phone model strings (or similar device-response
 * strings) into fixed-size fields, the result must be bounded by the
 * destination buffer size. No out-of-bounds write should occur.
 *
 * CWE-120: Buffer Copy without Checking Size of Input
 *
 * We simulate the vulnerable pattern:
 *   strcpy(value, s->Phone.Data.Model);
 * where 'value' is a fixed-size buffer and Model comes from an untrusted
 * device response.
 *
 * The safe replacement must use strncpy / strlcpy / snprintf with explicit
 * size limits. This test verifies that a safe copy function never writes
 * beyond the declared destination size.
 */

/* Destination buffer size as used in the real code (typical GSM_MAX_MODEL_LENGTH) */
#define MODEL_BUFFER_SIZE  64
#define DEBUG_LEVEL_SIZE   32

/* Canary value to detect out-of-bounds writes */
#define CANARY 0xAB

/*
 * safe_model_copy: the corrected version of the vulnerable strcpy call.
 * Returns 0 on success (possibly truncated), -1 if input is NULL.
 */
static int safe_model_copy(char *dest, size_t dest_size, const char *src)
{
    if (!dest || !src || dest_size == 0) return -1;
    strncpy(dest, src, dest_size - 1);
    dest[dest_size - 1] = '\0';
    return 0;
}

/*
 * safe_debug_copy: the corrected version for debug level strings.
 */
static int safe_debug_copy(char *dest, size_t dest_size, const char *src)
{
    if (!dest || !src || dest_size == 0) return -1;
    strncpy(dest, src, dest_size - 1);
    dest[dest_size - 1] = '\0';
    return 0;
}

/* Helper: build a string of given length filled with character c */
static char *make_string(size_t len, char c)
{
    char *s = (char *)malloc(len + 1);
    if (!s) return NULL;
    memset(s, c, len);
    s[len] = '\0';
    return s;
}

